section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "agent-ga-readiness-checklist-output",
  "required": [
    "items",
    "eval_bar_passed",
    "rollback_tested",
    "kill_switch_tested",
    "date",
    "signer",
    "forbidden_seen"
  ],
  "properties": {
    "items": {
      "description": "{name, status<done|skipped>, evidence_or_reason, owner}."
    },
    "eval_bar_passed": {
      "description": "5 consecutive green nightlies + \u226585%."
    },
    "rollback_tested": {
      "description": "True iff e2e tested."
    },
    "kill_switch_tested": {
      "description": "True iff verified."
    },
    "date": {
      "description": "Sign-off date."
    },
    "signer": {
      "description": "Owner name."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
